import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { z } from "zod";

const server = new McpServer({
  name: "weather-server",
  version: "1.0.0",
});

// Tool
server.tool(
  "get_weather",
  "Get current weather for a location",
  {
    location: z.string().describe("City name or zip code"),
    units: z.enum(["celsius", "fahrenheit"]).default("celsius"),
  },
  async ({ location, units }) => {
    const weather = await fetchWeather(location, units);
    return {
      content: [
        {
          type: "text",
          text: `Temperature: ${weather.temp}${units === "celsius" ? "C" : "F"}\nConditions: ${weather.conditions}`,
        },
      ],
    };
  }
);

// Resource (static)
server.resource(
  "config",
  "file:///app/config.json",
  { mimeType: "application/json" },
  async (uri) => {
    const content = await fs.readFile("/app/config.json", "utf-8");
    return {
      contents: [{ uri: uri.href, mimeType: "application/json", text: content }],
    };
  }
);

// Resource (dynamic template)
server.resourceTemplate(
  "project-file",
  "file:///{path}",
  { mimeType: "text/plain" },
  async (uri, { path }) => {
    const content = await fs.readFile(path, "utf-8");
    return {
      contents: [{ uri: uri.href, mimeType: "text/plain", text: content }],
    };
  }
);

// Prompt
server.prompt(
  "code_review",
  "Analyze code quality and suggest improvements",
  {
    code: z.string().describe("The code to review"),
    language: z.string().optional().describe("Programming language"),
  },
  async ({ code, language }) => {
    return {
      messages: [
        {
          role: "user",
          content: {
            type: "text",
            text: `Please review this ${language || "code"}:\n\n\`\`\`${language || ""}\n${code}\n\`\`\``,
          },
        },
      ],
    };
  }
);

const transport = new StdioServerTransport();
await server.connect(transport);

import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { z } from "zod";

const server = new McpServer({
  name: "database-server",
  version: "1.0.0",
  capabilities: {
    tools: { listChanged: true },
    resources: { subscribe: true, listChanged: true },
    prompts: { listChanged: true },
  },
});

server.tool(
  "execute_query",
  "Execute a read-only SQL query",
  {
    query: z.string().describe("SQL SELECT query"),
    database: z.string().default("main"),
  },
  async ({ query, database }) => {
    if (!/^\s*SELECT/i.test(query)) {
      return {
        content: [{ type: "text", text: "Only SELECT queries are allowed" }],
        isError: true,
      };
    }
    const results = await executeQuery(database, query);
    return {
      content: [{ type: "text", text: JSON.stringify(results, null, 2) }],
      structuredContent: results,
    };
  }
);

const transport = new StdioServerTransport();
await server.connect(transport);

from mcp.server.fastmcp import FastMCP
import json

mcp = FastMCP("project-tools")

@mcp.tool()
def query_database(sql: str) -> str:
    """Execute a read-only SQL query. Returns JSON rows."""
    import re
    if not re.match(r"^\s*SELECT\b", sql, re.IGNORECASE):
        raise ValueError("Only SELECT queries allowed")
    rows = db.execute(sql).fetchall()
    return json.dumps([dict(r) for r in rows])

@mcp.resource("file:///{path}")
def read_file(path: str) -> str:
    """Read a file from the project directory."""
    return Path(f"/project/{path}").read_text()

@mcp.prompt()
def code_review(code: str, language: str = "python") -> str:
    """Generate a code review prompt."""
    return f"Please review this {language} code:\n\n```{language}\n{code}\n```"

if __name__ == "__main__":
    mcp.run()  # stdio transport by default

from mcp.server import Server
from mcp.server.stdio import stdio_server
from mcp.types import Tool, TextContent

server = Server("weather-server")

@server.list_tools()
async def list_tools() -> list[Tool]:
    return [
        Tool(
            name="get_weather",
            description="Get current weather for a location",
            inputSchema={
                "type": "object",
                "properties": {
                    "location": {"type": "string", "description": "City name or zip code"},
                    "units": {"type": "string", "enum": ["celsius", "fahrenheit"], "default": "celsius"}
                },
                "required": ["location"]
            }
        )
    ]

@server.call_tool()
async def call_tool(name: str, arguments: dict) -> list[TextContent]:
    if name == "get_weather":
        location = arguments["location"]
        units = arguments.get("units", "celsius")
        weather = await fetch_weather(location, units)
        return [TextContent(
            type="text",
            text=f"Temperature: {weather['temp']}{units[0].upper()}\nConditions: {weather['conditions']}"
        )]
    raise ValueError(f"Unknown tool: {name}")

async def main():
    async with stdio_server() as (read_stream, write_stream):
        await server.run(read_stream, write_stream)

if __name__ == "__main__":
    import asyncio
    asyncio.run(main())

import express from "express";
import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { SSEServerTransport } from "@modelcontextprotocol/sdk/server/sse.js";

const app = express();
const server = new McpServer({
  name: "http-mcp-server",
  version: "1.0.0",
});

// Add tools, resources, prompts...

// SSE endpoint for MCP
app.get("/mcp/sse", async (req, res) => {
  const transport = new SSEServerTransport("/mcp/messages", res);
  await server.connect(transport);
});

// Message endpoint for client requests
app.post("/mcp/messages", express.json(), async (req, res) => {
  // Handle incoming messages
});

app.listen(3000, () => {
  console.log("MCP HTTP server running on port 3000");
});
